(window.webpackJsonp=window.webpackJsonp||[]).push([[208],{835:function(n,t){n.exports='\x3c!-- \ntitle: 01-Rust入门\nsort: \n--\x3e \n\n## 安装\n\n[安装文档](https://www.rust-lang.org/tools/install)\n\n```bash\nrustup update\t# 更新\nrustc --version\t# 版本 \nrustup doc\t\t# 本地文档\n```\n\n## 语法\n\n### HelloWorld\n\n```rust\nfn main(){\n  println!("{} World", "Hello");\n}\n\n// 编译\nrustc main.rs\n./main\n```\n\n### 基础\n\n```rust\n// 标量\nlet demo: i16 = 40404;\t\t// 有符号\nlet demo = 40404u16;\t\t\t// 无符号\nlet mut demo = String12; \t// 可变变量\n\n// 常量\nconst MILLION = 1_000_000;\n\n// 数据类型\nlet byte = b\'A\'\t\t// byte类型\n\n// 元组\nlet tup: (i32, f32, u8) = (404, 3.14, 1);\n// 数组\nlet week = [1,2,3,4,5,6,0];  \n\n// 条件分支\nif x == 0 {\n    println!("True");\n} else if x == 1 {\n    println!("False");\n} else {\n    println!("Error")\n}\n// 数组遍历\nfor day in week.iter() {\n    println!("{}", day)\n}\n// range, s\nfor number in (1..10).rev() {\n    println!("{}", number)\n}\n\n// 循环\nloop {\n  break;\n}\n\nwhile stop == true {\n  \n}\n```\n\n### 使用\n\n```rust\n// 获得输入\nlet mut input = String::new();\n// 错误处理\nstd::io::stdin().read_line(&mut input).expect("取得输入失败");\nprintln!("{}", input);\n\n// 字符串转数字\nlet input = input.trim().parse().expect("输入不为数字");\n\n// 比较\n// 类似Switch\nmatch input.cmp(&secret) {\n    Ordering::Less => println!("太小了"),\n    Ordering::Equal => println!("正好") ,\n    Ordering::Greater => println!("太大了"),\n}\n\n// 错误处理\nlet input = match input.trim().parse() {\n    Ok(num) => num,\n    Err(_) => {\n        println!("输入错误, 请重新输入: ");\n        continue;\n    }\n};\n```\n\n\n\n## Cargo\n\n> [包管理器](https://crates.io/)\n>\n> [安装](https://doc.rust-lang.org/cargo/getting-started/installation.html)\n\n```bash\ncargo new hello_cargo\ncargo check\t# 检查语法错误\ncargo build\t# 编译\ncargo run\t\t# 编译并执行\ncargo build --release\t# 发布编译\n\n# 添加依赖\nCargo.toml\n```\n\n'}}]);